"use strict";(self.webpackChunksite=self.webpackChunksite||[]).push([[2777],{8310:e=>{e.exports=JSON.parse('{"lang":"fr","resources":{"landing":{"meta":{"title":"Linguist - Traduire des pages web en toute confidentialit\xe9 | Extension de traduction pour Chrome et Firefox","description":"Extension de traduction pour Chrome et Firefox respectueuse de la vie priv\xe9e. Traduisez instantan\xe9ment des pages web enti\xe8res, du texte s\xe9lectionn\xe9, des sous-titres et des messages. Fonctionne hors ligne et permet d\'int\xe9grer vos propres services de traduction et API."},"navigation":{"features":{"content":"Fonctionnalit\xe9s"},"blog":{"content":"Blog"},"docs":{"content":"Documentation"},"github":{"content":"GitHub"}},"install":{"chrome":"Installer pour Chrome","firefox":"Installer pour Firefox"},"sections":{"hero":{"title":"Traduisez des pages web en toute fluidit\xe9","description":"Linguist est un traducteur pour navigateur flexible qui int\xe8gre les services de traduction les plus populaires.\\n\\nTraduisez des pages web enti\xe8res, du texte s\xe9lectionn\xe9, des sous-titres sur Netflix ou lors d\'appels vid\xe9o, ainsi que des messages priv\xe9s. \xc9coutez les traductions et enregistrez les plus importantes dans votre dictionnaire personnel pour apprendre de nouveaux mots, m\xeame hors ligne.\\n\\nLinguist est une alternative moderne et respectueuse de la vie priv\xe9e aux extensions de traduction comme Google Translate. Essayez-le gratuitement."},"opensource":{"title":"Open source","content":"Linguist est une extension de traduction gratuite et <0>open source</0>. Elle ne collecte ni ne vend les donn\xe9es des utilisateurs.\\n\\nVous pouvez <1>faire un don</1> pour soutenir Linguist et nous aider \xe0 maintenir notre ind\xe9pendance et un haut niveau de qualit\xe9.\\n\\nPartagez Linguist sur les r\xe9seaux sociaux pour aider d\'autres personnes \xe0 le d\xe9couvrir."},"support":{"title":"Assistance","content":"Si vous avez des questions, contactez-nous <0/>.\\nSi vous avez trouv\xe9 un bug et poss\xe9dez un compte GitHub, veuillez <1>signaler un probl\xe8me</1>."},"createdBy":{"content":"Cr\xe9\xe9 par <0/>."}},"features":{"title":"Fonctionnalit\xe9s","items":{"offlineTranslation":{"title":"Traduction hors ligne et confidentialit\xe9","content":"Traduisez du texte directement sur votre appareil gr\xe2ce au traducteur hors ligne int\xe9gr\xe9. Votre texte reste priv\xe9 et n\'est pas envoy\xe9 sur Internet.\\n\\nActivez cette fonctionnalit\xe9 dans les param\xe8tres pour garantir la confidentialit\xe9 de vos traductions lorsque vous traitez des e-mails, des documents ou des messages personnels.\\n\\nLe traducteur hors ligne vous permet \xe9galement de traduire des pages sans connexion Internet, ce qui est particuli\xe8rement pratique en voyage."},"fullPageTranslation":{"title":"Traduire des pages web enti\xe8res","content":"Une traduction de page compl\xe8te, rapide et de haute qualit\xe9 en quelques clics.\\n\\nUtilisez un raccourci clavier pour traduire instantan\xe9ment. Survolez le texte traduit pour afficher l\'original. Traduisez m\xeame les pages priv\xe9es accessibles apr\xe8s connexion ou prot\xe9g\xe9es par un acc\xe8s payant.\\n\\nConfigurez des r\xe8gles de traduction automatique en fonction de la langue ou du domaine de la page.\\n\\nLinguist adopte une approche minimaliste : l\'extension modifie uniquement le texte, pr\xe9servant ainsi la mise en page et votre confort de navigation.\\n\\nActivez la traduction en temps r\xe9el pour vos r\xe9unions multilingues sur Zoom, Google Meet et Microsoft Teams."},"selectedTextTranslation":{"title":"Traduire du texte s\xe9lectionn\xe9 sur n\'importe quel site","content":"Vous rencontrez des mots inconnus en lisant un article en ligne ?\\nS\xe9lectionnez simplement le texte sur la page et cliquez sur le bouton de traduction.\\n\\n\xc9coutez le texte original ainsi que sa traduction, et enregistrez les termes dans votre dictionnaire pour les r\xe9viser plus tard."},"textTranslation":{"title":"Traduction rapide de texte","content":"Besoin de traduire quelque chose rapidement ? Cliquez sur l\'ic\xf4ne Linguist et saisissez votre texte.\\n\\nPlus besoin de changer d\'onglet ou d\'ouvrir des sites de traduction. Traduisez directement depuis votre navigateur en utilisant le service de votre choix."},"knowledgeBase":{"title":"Construire votre base de connaissances personnelle","content":"Chaque traduction est enregistr\xe9e dans votre historique, et vous pouvez ajouter les termes importants \xe0 votre dictionnaire personnel. Effectuez des recherches dans votre dictionnaire et votre historique \xe0 tout moment.\\n\\nAucune information ne se perd, m\xeame lors de longues sessions de recherche ou d\'apprentissage.\\n\\nLe dictionnaire fonctionne hors ligne, ce qui fait de Linguist l\'outil id\xe9al pour l\'apprentissage des langues et pour les voyageurs ayant besoin d\'un acc\xe8s constant \xe0 leur vocabulaire."},"customTranslators":{"title":"Int\xe9grer des services de traduction et des API","content":"Linguist vous laisse choisir le service de traduction \xe0 utiliser.\\n\\nL\'extension prend en charge les fournisseurs les plus populaires tels que Google, Yandex et Microsoft, avec plus de 100 langues disponibles.\\n\\nSi le service dont vous avez besoin n\'est pas inclus, vous pouvez l\'ajouter en tant que <0>traducteur personnalis\xe9</0>.\\n\\nLes traducteurs personnalis\xe9s vous permettent d\'int\xe9grer n\'importe quel syst\xe8me de traduction : des services d\'intelligence artificielle modernes comme ChatGPT, DeepL, DeepSeek et Gemini, jusqu\'aux traducteurs locaux fonctionnant directement sur votre appareil, tels qu\'Ollama ou LibreTranslate."}}},"faq":{"title":"FAQ","items":{"whatIsLinguist":{"title":"Qu\'est-ce que Linguist ?","content":"Linguist est une extension de traduction pour Chrome et Firefox, con\xe7ue pour respecter votre vie priv\xe9e.\\n\\nElle vous permet de traduire des pages web enti\xe8res, du texte s\xe9lectionn\xe9, des sous-titres et des messages directement dans votre navigateur, sans avoir \xe0 ouvrir de sites de traduction externes."},"whyLinguist":{"title":"Pourquoi utiliser Linguist ?","content":"Il existe de nombreuses extensions pour traduire des pages web, et certains navigateurs int\xe8grent m\xeame leurs propres traducteurs. Alors, pourquoi choisir Linguist ?\\n\\nLa plupart des traducteurs int\xe9gr\xe9s et des extensions manquent de flexibilit\xe9. Beaucoup d\xe9pendent d\'un seul fournisseur comme Google Translate ou Microsoft Bing, tandis que Firefox propose son propre traducteur hors ligne. Dans la majorit\xe9 des cas, vous ne pouvez pas choisir le service qui correspond le mieux \xe0 vos besoins.\\n\\nSi la qualit\xe9 de traduction est insuffisante pour ce que vous faites, ou si l\'envoi de textes priv\xe9s \xe0 des services tiers vous pose probl\xe8me, de nombreux outils ne vous offrent aucune alternative satisfaisante.\\n\\nDe plus, beaucoup d\'outils se limitent \xe0 une seule t\xe2che : certains traduisent des pages enti\xe8res, d\'autres uniquement du texte s\xe9lectionn\xe9.\\n\\nParall\xe8lement, certaines extensions de traduction sont principalement ax\xe9es sur la mon\xe9tisation. Des fonctionnalit\xe9s comme l\'historique de traduction ou les dictionnaires personnels n\xe9cessitent parfois un abonnement, et m\xeame des options de base comme le mode sombre sont parfois payantes.\\n\\nLinguist adopte une approche diff\xe9rente. C\'est un outil de traduction pens\xe9 pour \xeatre pratique. Vous pouvez choisir le service de traduction qui vous convient le mieux, passer d\'un fournisseur \xe0 l\'autre, ou ajouter vos propres traducteurs personnalis\xe9s.\\n\\nLinguist centralise \xe9galement tous vos besoins : traduisez des pages web enti\xe8res, du texte s\xe9lectionn\xe9, des sous-titres et des messages, tout en conservant une trace de vos traductions importantes dans votre historique et votre dictionnaire personnel."},"theLinguistLogo":{"title":"Pourquoi le logo de Linguist est-il la tour de Babel ?","content":"Le logo de Linguist s\'inspire de la <wiki>tour de Babel</wiki>, l\'une des plus anciennes histoires sur le langage et la communication.\\n\\nSelon ce r\xe9cit, les humains parlaient autrefois une seule et m\xeame langue et ont tent\xe9 de construire une tour atteignant le ciel. La tour n\'a jamais \xe9t\xe9 achev\xe9e, et l\'humanit\xe9 s\'est retrouv\xe9e divis\xe9e par de multiples langues. Depuis lors, les barri\xe8res linguistiques ont souvent compliqu\xe9 la communication.\\n\\nLinguist a \xe9t\xe9 cr\xe9\xe9 pour aider \xe0 surmonter ce probl\xe8me.\\n\\nLa tour de Babel pr\xe9sente sur le logo rappelle cette histoire : une multitude de langues, de cultures, et l\'effort constant des \xeatres humains pour se comprendre. Linguist contribue \xe0 rapprocher les gens en rendant la traduction simple, flexible et accessible directement depuis votre navigateur.\\n\\nLe logo refl\xe8te \xe9galement l\'esprit du projet. Linguist n\'est pas une simple interface de plus pour \\"Google Translate\\". C\'est un outil con\xe7u par des personnes passionn\xe9es par les langues, la confidentialit\xe9 et les technologies ouvertes. La tour de Babel symbolise la curiosit\xe9, l\'apprentissage et l\'id\xe9e que les diff\xe9rences linguistiques devraient rassembler les gens plut\xf4t que de les diviser."},"imageTranslation":{"title":"Pourquoi Linguist ne traduit-il pas le texte sur les images ?","content":"Linguist se concentre sur des fonctionnalit\xe9s de traduction fiables et de haute qualit\xe9.\\n\\nNous avons \xe9tudi\xe9 diff\xe9rentes approches pour traduire le texte contenu dans les images. Actuellement, la plupart des solutions disponibles n\'offrent pas de r\xe9sultats constants, en particulier lorsqu\'elles s\'ex\xe9cutent directement dans le navigateur \u2014 un point essentiel pour garantir la confidentialit\xe9 des utilisateurs.\\n\\nC\'est pourquoi Linguist n\'int\xe8gre pas la traduction d\'images pour le moment. Nous pr\xe9f\xe9rons ne pas proposer de fonctionnalit\xe9s qui ne r\xe9pondent pas \xe0 nos crit\xe8res de qualit\xe9.\\n\\nSi nous trouvons \xe0 l\'avenir un moyen fiable et respectueux de la vie priv\xe9e d\'int\xe9grer la traduction d\'images, nous serons ravis de l\'ajouter."},"howTranslatePages":{"title":"Comment Linguist traduit-il les pages web ?","content":"Linguist peut traduire des pages web enti\xe8res en quelques clics. Vous pouvez lancer la traduction d\'une page \xe0 l\'aide du bouton de l\'extension ou d\'un raccourci clavier.\\n\\nLe texte original reste toujours accessible. Survolez simplement le texte traduit pour afficher la version d\'origine."},"offlineTranslation":{"title":"Linguist peut-il traduire des pages hors ligne ?","content":"Oui. Linguist int\xe8gre un traducteur hors ligne qui vous permet de traduire du texte sans envoyer de donn\xe9es sur Internet.\\n\\nCela garantit la protection de votre vie priv\xe9e et vous permet de traduire du contenu m\xeame sans connexion Internet."},"privacy":{"title":"Linguist respecte-t-il la vie priv\xe9e ?","content":"Oui. Linguist a \xe9t\xe9 con\xe7u en pla\xe7ant la confidentialit\xe9 au c\u0153ur de ses priorit\xe9s.\\n\\nL\'extension ne collecte ni ne vend les donn\xe9es des utilisateurs. Lorsque vous utilisez le <offline-translator>traducteur hors ligne</offline-translator>, les traductions sont trait\xe9es int\xe9gralement sur votre appareil."},"supportedBrowsers":{"title":"Quels navigateurs sont compatibles avec Linguist ?","content":"Linguist est disponible pour Chrome et Firefox. L\'extension fonctionne \xe9galement sur d\'autres navigateurs bas\xe9s sur Chromium qui prennent en charge les extensions Chrome.\\n\\nLinguist est aussi compatible avec les navigateurs Android acceptant les extensions, comme Firefox pour Android et certains navigateurs bas\xe9s sur Chromium."},"selectedText":{"title":"Linguist peut-il traduire du texte s\xe9lectionn\xe9 ?","content":"Oui. Il vous suffit de s\xe9lectionner du texte sur n\'importe quelle page web et d\'utiliser le bouton de traduction pour le traduire instantan\xe9ment.\\n\\nVous pouvez \xe9galement \xe9couter la traduction et l\'enregistrer dans votre dictionnaire personnel."},"customTranslators":{"title":"Puis-je utiliser mon propre service de traduction ?","content":"Oui. Linguist prend en charge les <custom-translator>traducteurs personnalis\xe9s</custom-translator>, ce qui vous permet d\'int\xe9grer des services de traduction suppl\xe9mentaires.\\n\\nVous pouvez connecter des API externes ou des syst\xe8mes de traduction locaux tels que <libre-translate>LibreTranslate</libre-translate> ou <ollama>Ollama</ollama>."},"isFree":{"title":"Linguist est-il gratuit ?","content":"Oui. Linguist est enti\xe8rement gratuit et <linguist>open source</linguist>.\\n\\nLe projet est soutenu par la communaut\xe9, et vous pouvez, si vous le souhaitez, <donations>le soutenir en faisant un don</donations>."}}}}},"altVersions":[{"langCode":"ar","langName":"\u0627\u0644\u0639\u0631\u0628\u064a\u0629","url":"https://linguister.io/ar"},{"langCode":"bg","langName":"\u0431\u044a\u043b\u0433\u0430\u0440\u0441\u043a\u0438","url":"https://linguister.io/bg"},{"langCode":"bn","langName":"\u09ac\u09be\u0982\u09b2\u09be","url":"https://linguister.io/bn"},{"langCode":"ca","langName":"catal\xe0","url":"https://linguister.io/ca"},{"langCode":"cs","langName":"\u010de\u0161tina","url":"https://linguister.io/cs"},{"langCode":"da","langName":"dansk","url":"https://linguister.io/da"},{"langCode":"de","langName":"Deutsch","url":"https://linguister.io/de"},{"langCode":"el","langName":"\u0395\u03bb\u03bb\u03b7\u03bd\u03b9\u03ba\u03ac","url":"https://linguister.io/el"},{"langCode":"en","langName":"English","url":"https://linguister.io/"},{"langCode":"es","langName":"espa\xf1ol","url":"https://linguister.io/es"},{"langCode":"fa","langName":"\u0641\u0627\u0631\u0633\u06cc","url":"https://linguister.io/fa"},{"langCode":"fi","langName":"suomi","url":"https://linguister.io/fi"},{"langCode":"fr","langName":"fran\xe7ais","url":"https://linguister.io/fr"},{"langCode":"gu","langName":"\u0a97\u0ac1\u0a9c\u0ab0\u0abe\u0aa4\u0ac0","url":"https://linguister.io/gu"},{"langCode":"he","langName":"\u05e2\u05d1\u05e8\u05d9\u05ea","url":"https://linguister.io/he"},{"langCode":"hi","langName":"\u0939\u093f\u0928\u094d\u0926\u0940","url":"https://linguister.io/hi"},{"langCode":"hu","langName":"magyar","url":"https://linguister.io/hu"},{"langCode":"id","langName":"Indonesia","url":"https://linguister.io/id"},{"langCode":"it","langName":"italiano","url":"https://linguister.io/it"},{"langCode":"ja","langName":"\u65e5\u672c\u8a9e","url":"https://linguister.io/ja"},{"langCode":"jv","langName":"Jawa","url":"https://linguister.io/jv"},{"langCode":"ka","langName":"\u10e5\u10d0\u10e0\u10d7\u10e3\u10da\u10d8","url":"https://linguister.io/ka"},{"langCode":"ko","langName":"\ud55c\uad6d\uc5b4","url":"https://linguister.io/ko"},{"langCode":"mr","langName":"\u092e\u0930\u093e\u0920\u0940","url":"https://linguister.io/mr"},{"langCode":"nb","langName":"norsk bokm\xe5l","url":"https://linguister.io/nb"},{"langCode":"nl","langName":"Nederlands","url":"https://linguister.io/nl"},{"langCode":"pa","langName":"\u0a2a\u0a70\u0a1c\u0a3e\u0a2c\u0a40","url":"https://linguister.io/pa"},{"langCode":"pl","langName":"polski","url":"https://linguister.io/pl"},{"langCode":"pt-BR","langName":"portugu\xeas (Brasil)","url":"https://linguister.io/pt-BR"},{"langCode":"pt-PT","langName":"portugu\xeas europeu","url":"https://linguister.io/pt-PT"},{"langCode":"ro","langName":"rom\xe2n\u0103","url":"https://linguister.io/ro"},{"langCode":"ru","langName":"\u0440\u0443\u0441\u0441\u043a\u0438\u0439","url":"https://linguister.io/ru"},{"langCode":"sl","langName":"sloven\u0161\u010dina","url":"https://linguister.io/sl"},{"langCode":"sr","langName":"\u0441\u0440\u043f\u0441\u043a\u0438","url":"https://linguister.io/sr"},{"langCode":"sv","langName":"svenska","url":"https://linguister.io/sv"},{"langCode":"ta","langName":"\u0ba4\u0bae\u0bbf\u0bb4\u0bcd","url":"https://linguister.io/ta"},{"langCode":"te","langName":"\u0c24\u0c46\u0c32\u0c41\u0c17\u0c41","url":"https://linguister.io/te"},{"langCode":"th","langName":"\u0e44\u0e17\u0e22","url":"https://linguister.io/th"},{"langCode":"tr","langName":"T\xfcrk\xe7e","url":"https://linguister.io/tr"},{"langCode":"uk","langName":"\u0443\u043a\u0440\u0430\u0457\u043d\u0441\u044c\u043a\u0430","url":"https://linguister.io/uk"},{"langCode":"ur","langName":"\u0627\u0631\u062f\u0648","url":"https://linguister.io/ur"},{"langCode":"vi","langName":"Ti\u1ebfng Vi\u1ec7t","url":"https://linguister.io/vi"},{"langCode":"zh-CN","langName":"\u4e2d\u6587\uff08\u4e2d\u56fd\uff09","url":"https://linguister.io/zh-CN"},{"langCode":"zh-TW","langName":"\u4e2d\u6587\uff08\u53f0\u7063\uff09","url":"https://linguister.io/zh-TW"}]}')}}]);